#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, P;
        scanf("%d %d %d", &N, &M, &P);
        double dp[N + 1][N + 1];
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= i; j++) {
                if (j == 0) dp[i][j] = 0;
                else if (j == i) dp[i][j] = 1;
                else dp[i][j] = (j * (P / 100.0) * (i - j) * 0.5 + (i - j) * (i - j - 1) * 0.5 * 0.5) / (i * (i - 1) * 0.5);
            }
        }
        double ans = 0;
        for (int i = 0; i < M; i++) {
            int x;
            scanf("%d", &x);
            ans += dp[N][1];
        }
        printf("%.6f\n", ans);
    }
    return 0;
}

